import { CancellationToken } from '../../../../base/common/cancellation.js';
import { ITextModel } from '../../../common/model.js';
import { FoldingRegions, MAX_LINE_NUMBER } from './foldingRanges.js';
import { FoldingLimitReporter, RangeProvider } from './folding.js';

const ID_NAMED_REGION_PROVIDER = 'namedRegion';
const MAX_FOLDING_REGIONS_FOR_NAMED_DEFAULT = 5000;

export interface NamedRegionInfo {
	name: string;
	startLineNumber: number;
	endLineNumber: number;
	index: number;
}

/**
 * Detects and extracts named folding regions marked with #region/#endregion comments.
 * Supports extracting region names from markers like: // #region MyRegionName
 * Also supports: /* #region MyRegionName */ for block comments
 */
export class NamedRegionProvider implements RangeProvider {
	readonly id = ID_NAMED_REGION_PROVIDER;

	constructor(
		private readonly editorModel: ITextModel,
		private readonly foldingRangesLimit: FoldingLimitReporter
	) { }

	dispose() { }

	compute(cancellationToken: CancellationToken): Promise<FoldingRegions | null> {
		return Promise.resolve(this.computeNamedRegions());
	}

	private computeNamedRegions(): FoldingRegions | null {
		const lineCount = this.editorModel.getLineCount();
		const startIndexes: number[] = [];
		const endIndexes: number[] = [];
		const names: (string | undefined)[] = [];

		const regionStack: Array<{ startLine: number; name?: string }> = [];

		for (let lineNumber = 1; lineNumber <= lineCount; lineNumber++) {
			const lineContent = this.editorModel.getLineContent(lineNumber);

			// Check for #region marker (matches // #region Name, # #region Name, etc.)
			const regionMatch = lineContent.match(/#region\s+(.+?)(?:\s*\(|$)/);
			if (regionMatch) {
				const regionName = regionMatch[1].trim();
				regionStack.push({ startLine: lineNumber, name: regionName });
				continue;
			}

			// Also match #region without a name
			if (lineContent.includes('#region') && !regionMatch) {
				regionStack.push({ startLine: lineNumber, name: undefined });
				continue;
			}

			// Check for #endregion marker
			if (lineContent.includes('#endregion')) {
				if (regionStack.length > 0) {
					const region = regionStack.pop()!;
					const startLine = region.startLine;
					const endLine = lineNumber;

					if (endLine - startLine >= 1 && startLine <= MAX_LINE_NUMBER && endLine <= MAX_LINE_NUMBER) {
						startIndexes.push(startLine);
						endIndexes.push(endLine);
						names.push(region.name);
					}
				}
			}
		}

		if (startIndexes.length === 0) {
			return null;
		}

		const limit = Math.min(startIndexes.length, MAX_FOLDING_REGIONS_FOR_NAMED_DEFAULT);
		this.foldingRangesLimit.update(startIndexes.length, startIndexes.length > limit ? limit : false);

		// Create FoldingRegions with region names
		const result = new FoldingRegions(
			new Uint32Array(startIndexes),
			new Uint32Array(endIndexes),
			undefined, // types not used for named regions
			names.length > 0 ? names : undefined // names array
		);

		return result;
	}
}

