			'// #region First',
			'code here',
			'// #endregion',
			'// #endregion' // extra endregion - should be ignored
		];
		await assertNamedRegions(lines, [
			{ startLineNumber: 1, endLineNumber: 3, name: 'First' }
		]);
	});

	test('Region with leading whitespace', async () => {
		const lines = [
			'	// #region Indented',
			'	code here',
			'	// #endregion'
		];
		await assertNamedRegions(lines, [
			{ startLineNumber: 1, endLineNumber: 3, name: 'Indented' }
		]);
	});
});

